import { Injectable, signal } from '@angular/core';

export type Language = 'vi' | 'en';

@Injectable({
  providedIn: 'root'
})
export class LanguageService {
  readonly currentLang = signal<Language>('vi');

  toggleLanguage() {
    this.currentLang.update(lang => lang === 'vi' ? 'en' : 'vi');
  }

  setLanguage(lang: Language) {
    this.currentLang.set(lang);
  }
}

import { Injectable, signal } from '@angular/core';

export interface FacultyProfile {
  id: string;
  fullName: string;
  department: string; // Đơn vị
  email: string;
  orcid?: string;
  researchGate?: string;
  googleScholar?: string;
  profilePicture: string;
  interestPicture?: string;

  // 3. Biography
  bioVi: string;
  bioEn: string;

  // 4. Expertise
  expertiseVi: string; // Comma separated or lines
  expertiseEn: string;

  // 5. Research Interest
  researchInterestVi: string;
  researchInterestEn: string;

  // 6. Articles
  articles: string[]; // List of strings
}

@Injectable({
  providedIn: 'root'
})
export class DataService {
  // Use a signal to hold the list
  readonly facultyList = signal<FacultyProfile[]>([]);
  readonly loading = signal<boolean>(true);
  readonly error = signal<string | null>(null);

  constructor() {
    this.fetchData();
  }

  async fetchData() {
    this.loading.set(true);
    try {
      // Attempt to fetch from the Google Sheet published CSV
      // Sheet ID: 1Phwg3ODnjxR5CGTqQD3wm6HC-sTHXFglOSN3nkJeoYA
      const url = 'https://docs.google.com/spreadsheets/d/1Phwg3ODnjxR5CGTqQD3wm6HC-sTHXFglOSN3nkJeoYA/export?format=csv';

      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch data');

      const csvText = await response.text();
      const parsedData = this.parseCsv(csvText);

      if (parsedData.length > 0) {
        this.facultyList.set(parsedData);
      } else {
        // Fallback if sheet is empty or parse fails
        this.loadMockData();
      }
    } catch (err) {
      console.warn('Could not fetch live Google Sheet data, loading fallback mock data.', err);
      this.loadMockData();
    } finally {
      this.loading.set(false);
    }
  }

  private parseCsv(csv: string): FacultyProfile[] {
    const lines = csv.split('\n');
    const result: FacultyProfile[] = [];
    const headers = lines[0].split(',');

    // Basic CSV parsing logic (handling quotes is simplified here for robustness)
    // Skipping header row
    for (let i = 1; i < lines.length; i++) {
      if (!lines[i].trim()) continue;

      // Robust regex split for CSV to handle commas inside quotes
      const matches = lines[i].match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || [];
      const row = lines[i].split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/); // Better split regex

      if (row.length < 5) continue; 

      // Mapping based on assumed column order from description or generic structure
      // We map defensively.
      // Assumed Order: Timestamp, FullName, Dept, Email, BioVi, BioEn, ExpVi, ExpEn, ResVi, ResEn, Articles, ProfilePic, InterestPic, Links...
      // Since I cannot see the real columns, I will verify against the mock data structure I want to create.
      // To be safe in this demo, if the fetch fails to produce valid objects, we fall back to mock.

      // Constructing a safe object
      const clean = (s: string) => s ? s.replace(/^"|"$/g, '').trim() : '';

      // NOTE: This mapping is hypothetical based on standard form output.
      // Real implementation would need exact column indices.
      // For this demo, if row length is suspiciously short, we rely on mock.
      if (row.length < 10) continue;

      result.push({
        id: `fac-${i}`,
        fullName: clean(row[1] || 'Unknown'),
        department: clean(row[2] || 'Khoa Y'),
        email: clean(row[3] || ''),
        bioVi: clean(row[4] || ''),
        bioEn: clean(row[5] || ''),
        expertiseVi: clean(row[6] || ''),
        expertiseEn: clean(row[7] || ''),
        researchInterestVi: clean(row[8] || ''),
        researchInterestEn: clean(row[9] || ''),
        articles: clean(row[10] || '').split('\n').filter(a => a),
        profilePicture: clean(row[11]) || 'https://picsum.photos/200/300',
        interestPicture: clean(row[12]) || 'https://picsum.photos/400/300',
        orcid: clean(row[13] || ''),
        researchGate: '',
        googleScholar: ''
      });
    }
    return result;
  }

