export class FacultyListComponent {
  dataService = inject(DataService);
  langService = inject(LanguageService);

  lang = this.langService.currentLang;

  searchQuery = signal('');
  deptFilter = signal('');
  interestFilter = signal('');

  // Extract unique departments for filter dropdown
  departments = computed(() => {
    const list = this.dataService.facultyList();
    const depts = new Set(list.map(f => f.department).filter(Boolean));
    return Array.from(depts).sort();
  });

  filteredList = computed(() => {
    const list = this.dataService.facultyList();
    const q = this.searchQuery().toLowerCase();
    const d = this.deptFilter();
    const i = this.interestFilter().toLowerCase();
    const l = this.lang();

    return list.filter(item => {
      const matchName = item.fullName.toLowerCase().includes(q);
      const matchDept = d ? item.department === d : true;
      const matchInterest = l === 'vi' 
        ? item.researchInterestVi.toLowerCase().includes(i) 
        : item.researchInterestEn.toLowerCase().includes(i);

      return matchName && matchDept && matchInterest;
    });
  });

  updateSearch(e: Event) {
    this.searchQuery.set((e.target as HTMLInputElement).value);
  }

  updateDeptFilter(e: Event) {
    this.deptFilter.set((e.target as HTMLSelectElement).value);
  }

  updateInterestFilter(e: Event) {
    this.interestFilter.set((e.target as HTMLInputElement).value);
  }
}

