import { Injectable, signal } from '@angular/core';

export interface FacultyProfile {
  id: string;
  fullName: string;
  department: string; // Đơn vị
  email: string;
  orcid?: string;
  researchGate?: string;
  googleScholar?: string;
  profilePicture: string;
  interestPicture?: string;

  // 3. Biography
  bioVi: string;
  bioEn: string;

  // 4. Expertise
  expertiseVi: string; // Comma separated or lines
  expertiseEn: string;

  // 5. Research Interest
  researchInterestVi: string;
  researchInterestEn: string;

  // 6. Articles
  articles: string[]; // List of strings
}

@Injectable({
  providedIn: 'root'
})
export class DataService {
  // Use a signal to hold the list
  readonly facultyList = signal<FacultyProfile[]>([]);
  readonly loading = signal<boolean>(true);
  readonly error = signal<string | null>(null);

  constructor() {
    this.fetchData();
  }

  async fetchData() {
    this.loading.set(true);
    try {
      // Attempt to fetch from the Google Sheet published CSV
      // Sheet ID: 1Phwg3ODnjxR5CGTqQD3wm6HC-sTHXFglOSN3nkJeoYA
      const url = 'https://docs.google.com/spreadsheets/d/1Phwg3ODnjxR5CGTqQD3wm6HC-sTHXFglOSN3nkJeoYA/export?format=csv';

      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch data');

      const csvText = await response.text();
      const parsedData = this.parseCsv(csvText);

      if (parsedData.length > 0) {
        this.facultyList.set(parsedData);
      } else {
        // Fallback if sheet is empty or parse fails
        this.loadMockData();
      }
    } catch (err) {
      console.warn('Could not fetch live Google Sheet data, loading fallback mock data.', err);
      this.loadMockData();
    } finally {
      this.loading.set(false);
    }
  }

  private parseCsv(csv: string): FacultyProfile[] {
    const lines = csv.split('\n');
    const result: FacultyProfile[] = [];

    // Skip header row
    for (let i = 1; i < lines.length; i++) {
      if (!lines[i].trim()) continue;

      // Robust regex split for CSV to handle commas inside quotes
      // This splits by comma ONLY if that comma is followed by an even number of quotes (meaning it's outside quotes)
      const row = lines[i].split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/);

      // Clean function to remove quotes
      const clean = (s: string) => s ? s.replace(/^"|"$/g, '').trim() : '';

      // Mapping based on User Instruction:
      // Index 0: Timestamp (Col A)
      // Index 1: Profile Picture (Col B - 1.1)
      // Index 2: Email (Guessing Col C)
      // Index 3, 4: (Reserved/Unknown)
      // Index 5: Bio VI (Guessing Col F based on J=9)
      // Index 6: Bio EN (Guessing Col G)
      // Index 7: Expertise VI (Guessing Col H)
      // Index 8: Expertise EN (Guessing Col I)
      // Index 9: Research Interest VI (Col J - 5.1 - Confirmed)
      // Index 10: Research Interest EN (Col K - 5.2 - Confirmed)
      // Index 11: Articles (Guessing Col L - 6)
      // Index 12: Full Name (Col M - Confirmed)
      // Index 13: (Unknown - maybe academic rank?)
      // Index 14: Department (Col O - Confirmed)
      // Index 15: Interest Picture (Guessing Col P or using placeholder)

      // Ensure we have enough columns to avoid errors, assuming at least up to Dept (15 columns)
      if (row.length < 10) continue; 

      const fullName = clean(row[12] || ''); // Col M
      // If name is empty, likely an empty row or bad data
      if (!fullName) continue;

      result.push({
        id: `fac-${i}`,
        fullName: fullName, 
        department: clean(row[14] || 'CTUMP'), // Col O
        email: clean(row[2] || ''), // Col C (Assumption)

        // Col B: Profile Picture
        profilePicture: clean(row[1]) || 'https://picsum.photos/200/300',

        // Bio (Assumed F & G)
        bioVi: clean(row[5] || ''),
        bioEn: clean(row[6] || ''),

        // Expertise (Assumed H & I)
        expertiseVi: clean(row[7] || ''),
        expertiseEn: clean(row[8] || ''),

        // Research Interest (Col J & K)
        researchInterestVi: clean(row[9] || ''),
        researchInterestEn: clean(row[10] || ''),

        // Articles (Assumed L)
        articles: clean(row[11] || '').split(/\n|;/).map(a => a.trim()).filter(a => a.length > 0),

        // Interest Picture (Assumed P or fallback)
        interestPicture: clean(row[15] || '') || 'https://picsum.photos/400/300',

        orcid: '',
        researchGate: '',
        googleScholar: ''
      });
    }
    return result;
  }

  private loadMockData() {
    const mocks: FacultyProfile[] = [
      {
        id: '1',
        fullName: 'PGS.TS. Nguyễn Văn A',
        department: 'Khoa Dược (Faculty of Pharmacy)',
        email: 'nva@ctump.edu.vn',
        orcid: '0000-0001-2345-6789',
        researchGate: 'https://researchgate.net',
        googleScholar: 'https://scholar.google.com',
        profilePicture: 'https://picsum.photos/id/1012/300/400',
        interestPicture: 'https://picsum.photos/id/1059/400/300',
        bioVi: 'PGS.TS. Nguyễn Văn A hiện là giảng viên Bộ môn Dược lý, Khoa Dược, Trường Đại học Y Dược Cần Thơ. Hướng nghiên cứu chủ lực tập trung vào các nghiên cứu về đề kháng kháng sinh.',
        bioEn: 'Assoc. Prof. Ph.D. Nguyen Van A is currently a lecturer at the Department of Pharmacology, Faculty of Pharmacy. His main research direction focuses on antibiotic resistance studies.',
        expertiseVi: 'Dược lý\nKhoa học thần kinh',
        expertiseEn: 'Pharmacology\nNeuroscience',
        researchInterestVi: 'Đề kháng kháng sinh\nDược động học',
        researchInterestEn: 'Antibiotic resistance\nPharmacokinetics',
        articles: [
          'Nguyen VA et al. (2023). Antibiotic resistance patterns in Mekong Delta. J Med Res.',
          'Tran TB, Nguyen VA. (2022). Neuroprotective effects of herbal extracts. Phytomedicine.'
        ]
      },
      {
        id: '2',
        fullName: 'TS. Trần Thị B',
        department: 'Khoa Y tế Công cộng',
        email: 'ttb@ctump.edu.vn',
        orcid: '0000-0002-9876-5432',
        profilePicture: 'https://picsum.photos/id/1027/300/400',
        interestPicture: 'https://picsum.photos/id/1084/400/300',
        bioVi: 'TS. Trần Thị B là chuyên gia về Y tế công cộng với hơn 15 năm kinh nghiệm giảng dạy và nghiên cứu.',
        bioEn: 'Dr. Tran Thi B is a Public Health expert with over 15 years of teaching and research experience.',
        expertiseVi: 'Sức khỏe môi trường',
        expertiseEn: 'Environmental Health',
