    // 3. Replace multiple spaces with single space
    // 4. Trim ends
    const clean = trimmed.toLowerCase()
      .replace(/\./g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    // KEEP ORIGINAL DATA
    let vi = trimmed; 
    let en = trimmed; 
    let priority = 99; 

    // STRICT COMPARISON LOGIC (Must START WITH...)

    // 1. PROFESSOR (GS)
