import { Injectable, signal } from '@angular/core';

export interface FacultyProfile {
  id: string;
  fullName: string;

  // Academic Titles
  academicTitle: string;    // Vietnamese (e.g., PGS. TS.)
  academicTitleEn: string;  // English (e.g., Assoc. Prof. Ph.D.)

  // Sorting Priority (Lower is higher in list)
  // 1 = GS, 2 = PGS, 3 = TS, 99 = Others
  sortPriority: number;     

  department: string;   // Vietnamese Name
  departmentEn: string; // English Name
  email: string;
  orcid?: string;
  researchGate?: string;
  googleScholar?: string;
  profilePicture: string;
  interestPicture?: string;

  // Biography
  bioVi: string;
  bioEn: string;

  // Expertise
  expertiseVi: string;
  expertiseEn: string;

  // Research Interest Strings (Raw)
  researchInterestVi: string;
  researchInterestEn: string;

  // Research Interest Tags (Processed - Array)
  researchInterestViTags: string[];
  researchInterestEnTags: string[];

  // Articles
  articles: string[];
}

@Injectable({
  providedIn: 'root'
})
export class DataService {
  readonly facultyList = signal<FacultyProfile[]>([]);
  readonly loading = signal<boolean>(true);
  readonly error = signal<string | null>(null);

  constructor() {
    this.fetchData();
  }

  async fetchData() {
    this.loading.set(true);
    try {
      // Google Sheet export link
      const url = 'https://docs.google.com/spreadsheets/d/1Phwg3ODnjxR5CGTqQD3wm6HC-sTHXFglOSN3nkJeoYA/export?format=csv';

      const response = await fetch(url);
      if (!response.ok) throw new Error('Failed to fetch data');

      const csvText = await response.text();
      const parsedData = this.parseCsvRobust(csvText);

      if (parsedData.length > 0) {
        this.facultyList.set(parsedData);
      } else {
        console.warn('Parsed data is empty, loading mock data.');
        this.loadMockData();
      }
    } catch (err) {
      console.error('Error fetching/parsing CSV:', err);
      this.loadMockData();
    } finally {
      this.loading.set(false);
    }
  }

  /**
   * Helper to convert Google Drive links to direct image links.
   */
  private convertGoogleDriveUrl(url: string): string {
    if (!url) return '';
    if (url.includes('drive.google.com')) {
      const match = url.match(/(?:\/d\/|id=)([-\w]+)/);
      if (match && match[1]) {
        return `https://lh3.googleusercontent.com/d/${match[1]}`;
      }
    }
    return url;
  }

  /**
   * ADVANCED TAG CLEANER
   */
  private cleanResearchTags(text: string, lang: 'vi' | 'en'): string[] {
    if (!text) return [];

    let processed = text
      .replace(/[\n\r]+/g, '|')
      .replace(/•|–|—|\+/g, '|')
      .replace(/(^|\|)\s*\d+[\.\)]/g, '|')
      .replace(/[,;]/g, '|');

    let items = processed.split('|');

    const cleanedItems = items.map(item => {
      let clean = item.trim();
      clean = clean.replace(/^[\-\.\:\s]+/, '');

      if (lang === 'vi') {
        clean = clean.replace(/^(nghiên cứu (về|các)|các vấn đề (về|liên quan)|tìm hiểu|lĩnh vực|chuyên ngành|định hướng)\s+/i, '');
        clean = clean.replace(/^về\s+/i, '');
      } else {
        clean = clean.replace(/^(research (on|in|into|about)|study (of|on)|focus (on|in)|field of|related to)\s+/i, '');
      }

      clean = clean.trim();
      if (clean.length > 0) {
        clean = clean.charAt(0).toUpperCase() + clean.slice(1);
      }
      return clean;
    });

    return cleanedItems.filter(item => {
      if (item.length < 3) return false;
      if (item.length > 80) return false; 
      if (/^[^a-zA-Zà-ỹÀ-Ỹ]+$/.test(item)) return false;
      return true;
    });
  }

  /**
   * Normalize Department Names
   */
  private processDepartment(rawDept: string): { vi: string, en: string } {
    let d = rawDept ? rawDept.trim() : '';

    const normalizationMap: Record<string, string> = {
      'Khoa KHCB': 'Khoa Khoa học Cơ bản',
      'Khoa Điều dưỡng & KTYH': 'Khoa Điều dưỡng và Kỹ thuật Y Học',
      'Khoa YTCC': 'Khoa Y tế Công cộng',
      'Khoa YHCT': 'Khoa Y học Cổ Truyền',
      'Phòng ĐT Sau Đại học': 'Phòng Đào tạo Sau Đại học',
      'Khoa RHM': 'Khoa Răng Hàm Mặt'
    };

    let vi = normalizationMap[d] || d;

    if (!vi) {
      return { vi: 'Khoa Y', en: 'Faculty of Medicine' };
    }

    const translationMap: Record<string, string> = {
      'Khoa Khoa học Cơ bản': 'Faculty of Basic Sciences',
      'Khoa Điều dưỡng và Kỹ thuật Y Học': 'Faculty of Nursing and Medical Technology',
      'Khoa Y': 'Faculty of Medicine',
      'Khoa Dược': 'Faculty of Pharmacy',
      'Khoa Y tế Công cộng': 'Faculty of Public Health',
      'Khoa Y học Cổ Truyền': 'Faculty of Traditional Medicine',
      'Khoa Răng Hàm Mặt': 'Faculty of Odonto-Stomatology',
      'Phòng Đào tạo Sau Đại học': 'Post-Graduate Training Office'
    };

    let en = translationMap[vi];
    if (!en) {
      en = vi;
    }

    return { vi, en };
  }

  /**
   * Process Academic Title
   * 
   * PRIORITY LOGIC (Ascending Sort):
   * 1. GS (Prof) - Highest
   * 2. PGS (Assoc Prof)
   * 3. TS (PhD)
   * 99. Others - Lowest
   */
  private processAcademicTitle(raw: string): { vi: string, en: string, priority: number } {
    const trimmed = raw ? raw.trim() : '';

    // Aggressive Cleaning for detection:
    // 1. Lowercase
    // 2. Remove dots, commas, colons (replace with space)
    // 3. Collapse multiple spaces
    // e.g. "PGS. TS." -> "pgs ts"
    // e.g. "PGS,TS" -> "pgs ts"
    const clean = trimmed.toLowerCase()
      .replace(/[.,;:\-]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    // KEEP ORIGINAL DATA for display
    let vi = trimmed; 
    let en = trimmed; 
    let priority = 99; 

    // STRICT COMPARISON LOGIC (STARTS WITH)
    // Because we cleaned punctuation, we can safely check "startsWith".

    // 1. CHECK PGS (Priority 2)
    // Matches "pgs ts...", "pgs...", "pho gs..."
    // Note: Must be checked distinct from "GS". 
    // "pgs" starts with 'p', so it will NEVER be caught by 'gs'.
    if (clean.startsWith('pgs') || clean.startsWith('pho gs') || clean.startsWith('pho giao su')) {
      priority = 2; 
      en = 'Assoc. Prof. Ph.D.';
    }

    // 2. CHECK GS (Priority 1)
    // Matches "gs ts...", "gs...", "giao su..."
    else if (clean.startsWith('gs') || clean.startsWith('giao su')) {
      priority = 1;
      en = 'Prof. Ph.D.';
    }

    // 3. CHECK TS (Priority 3)
    // Matches "ts...", "tien si..."
    // Because we use 'else if' and 'startsWith', "PGS" (starts with P) will never fall into this 'TS' (starts with T) bucket.
    else if (clean.startsWith('ts') || clean.startsWith('tien si') || clean.startsWith('phd')) {
      priority = 3;

      // Handle Medical Doctor combination for English translation
      if (clean.includes('bs')) {
         en = 'Ph.D. MD.';
      } else {
         en = 'Ph.D.';
      }
    }

    // 99. OTHERS
    else {
      priority = 99;
      // Basic substitution for English translation
      let tempEn = vi;
      if (tempEn.includes('ThS')) tempEn = tempEn.replace('ThS', 'MSc');
      if (tempEn.includes('BS')) tempEn = tempEn.replace('BS', 'MD');
      if (tempEn.includes('DS')) tempEn = tempEn.replace('DS', 'Pharm');
      if (tempEn.includes('CKII')) tempEn = tempEn.replace('CKII', 'II');
      if (tempEn.includes('CKI')) tempEn = tempEn.replace('CKI', 'I');
      en = tempEn;
    }

    return { vi, en, priority };
  }

  private parseCsvRobust(text: string): FacultyProfile[] {
    const rows: string[][] = [];
    let currentRow: string[] = [];
    let currentVal = '';
    let inQuotes = false;

    for (let i = 0; i < text.length; i++) {
      const char = text[i];
      const nextChar = text[i + 1];

      if (char === '"') {
        if (inQuotes && nextChar === '"') {
          currentVal += '"';
          i++; 
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === ',' && !inQuotes) {
        currentRow.push(currentVal);
        currentVal = '';
      } else if ((char === '\r' || char === '\n') && !inQuotes) {
        if (currentVal || currentRow.length > 0) {
          currentRow.push(currentVal);
        }
        if (currentRow.length > 0) {
          rows.push(currentRow);
        }
        currentRow = [];
        currentVal = '';
        if (char === '\r' && nextChar === '\n') i++;
      } else {
        currentVal += char;
      }
    }
    if (currentRow.length > 0 || currentVal) {
      currentRow.push(currentVal);
      rows.push(currentRow);
    }

    const result: FacultyProfile[] = [];

    // Column Indices (0-based)
    const col_B_Avatar = 1;
    const col_C_ORCID = 2;
    const col_D_RG = 3;
    const col_E_GS = 4;
    const col_F_ExpVi = 5;
    const col_G_ExpEn = 6;
    const col_H_BioVi = 7;
    const col_I_BioEn = 8;
    const col_J_IntVi = 9;
    const col_K_IntEn = 10;

    const col_L_Art1 = 11;
    const col_M_Name = 12;
    const col_O_Dept = 14;

    const col_P_Art2 = 15;
    const col_Q_Art3 = 16;
    const col_R_Art4 = 17;
    const col_S_Art5 = 18;

    const col_T_Img = 19; 
    const col_V_Email = 21; 
    const col_W_Title = 22; 

    for (let i = 1; i < rows.length; i++) {
      const row = rows[i];
      const get = (idx: number) => (row[idx] ? row[idx].trim() : '');

      const fullName = get(col_M_Name);
      if (!fullName) continue;

      const rawAvatarUrl = get(col_B_Avatar);
      const processedAvatarUrl = this.convertGoogleDriveUrl(rawAvatarUrl) || 'https://picsum.photos/300/400';

      const rawInterestImg = get(col_T_Img);
      const processedInterestImg = this.convertGoogleDriveUrl(rawInterestImg);

      const rawInterestVi = get(col_J_IntVi);
      const rawInterestEn = get(col_K_IntEn);

      // Process Department
      const rawDept = get(col_O_Dept);
      const deptInfo = this.processDepartment(rawDept);

      // Process Academic Title & Priority
      const rawTitle = get(col_W_Title);
      const titleInfo = this.processAcademicTitle(rawTitle);

      const rawArticles = [
        get(col_L_Art1),
        get(col_P_Art2),
        get(col_Q_Art3),
        get(col_R_Art4),
        get(col_S_Art5)
      ].filter(a => a.length > 5);

      result.push({
        id: `fac-${i}`,
        fullName: fullName,

        academicTitle: titleInfo.vi,
        academicTitleEn: titleInfo.en,
        sortPriority: titleInfo.priority, // Use priority number (1,2,3)

        profilePicture: processedAvatarUrl,

        department: deptInfo.vi,
        departmentEn: deptInfo.en,

        email: get(col_V_Email),
        orcid: get(col_C_ORCID),
        researchGate: get(col_D_RG),
        googleScholar: get(col_E_GS),

        bioVi: get(col_H_BioVi), 
        bioEn: get(col_I_BioEn), 

        expertiseVi: get(col_F_ExpVi), 
        expertiseEn: get(col_G_ExpEn),

        researchInterestVi: rawInterestVi,
        researchInterestEn: rawInterestEn,

        researchInterestViTags: this.cleanResearchTags(rawInterestVi, 'vi'),
        researchInterestEnTags: this.cleanResearchTags(rawInterestEn, 'en'),

        articles: rawArticles,

        interestPicture: processedInterestImg,
      });
    }

    // SORTING LOGIC:
    // 1. By Priority ASCENDING (1 -> 2 -> 3 -> 99)
    // 2. Then by First Name Alphabetically (A-Z)
    result.sort((a, b) => {
      // 1. Primary Sort: Priority (Lower number = Higher Rank)
      // 1 (GS) < 2 (PGS) < 3 (TS)
      if (a.sortPriority !== b.sortPriority) {
        return a.sortPriority - b.sortPriority;
      }

      // 2. Secondary Sort: First Name (Last word of full name)
      const nameA = a.fullName.trim().split(/\s+/).pop() || '';
      const nameB = b.fullName.trim().split(/\s+/).pop() || '';

      const nameComparison = nameA.localeCompare(nameB, 'vi');

      if (nameComparison !== 0) {
        return nameComparison;
      }

      // 3. Tertiary Sort: Full Name string
      return a.fullName.localeCompare(b.fullName, 'vi');
    });

    return result;
  }

