      ? this.faculty().researchInterestVi 
      : this.faculty().researchInterestEn;

    if (!raw) return [];

    // ONLY split by new lines. Preserve hyphens (-), dashes, bullets etc.
    // This fixes the issue where hyphens in text caused unwanted line breaks.
    return raw.split(/\r?\n/)
      .map(s => s.trim())
      .filter(s => s.length > 0);
  }
